-- migration: phase 4 — critical user flow analysis and missing indexes
-- purpose: analyze query plans for the 6 most critical user flows and add
--          missing indexes where the planner would choose suboptimal plans.
--
-- methodology: for each flow, we examined:
--   1. the PostgREST query generated by the frontend hook
--   2. the RLS policy applied to that query
--   3. the combined effective query after RLS injection
--   4. available indexes for the WHERE, JOIN, and ORDER BY clauses
--
-- ============================================================================
-- flow 1: OWNER DASHBOARD — get_dashboard_data_v2(p_user_id)
-- ============================================================================
-- effective queries (from the unified RPC):
--   properties WHERE owner_user_id = $1 AND status != 'inactive'
--   units WHERE property_id IN (owner_properties)
--   leases JOIN units WHERE owner_user_id = $1
--   maintenance_requests WHERE owner_user_id = $1
--   activity WHERE user_id = $1 ORDER BY created_at DESC LIMIT 10
--
-- index coverage:
--   properties: idx_properties_owner_user_id (owner_user_id) — covers filter
--   units: idx_units_property_id (property_id) — covers IN subquery
--   leases: idx_leases_owner_status (owner_user_id, lease_status) — covers filter
--   maintenance_requests: idx_maintenance_requests_owner_status (owner_user_id, status) — covers filter
--   activity: idx_activity_user_created_desc (user_id, created_at DESC) — covers filter + sort
--
-- verdict: FULLY INDEXED. no changes needed.

-- ============================================================================
-- flow 2: PROPERTY LIST — paginated with status/type filters
-- ============================================================================
-- frontend query:
--   .from('properties').select('*', { count: 'exact' })
--   .neq('status', 'inactive')
--   .order('created_at', { ascending: false })
--   + optional .eq('property_type', ...) and .or('name.ilike, city.ilike')
--
-- RLS adds: WHERE owner_user_id = auth.uid()
--
-- effective: WHERE owner_user_id = $1 AND status != 'inactive'
--            ORDER BY created_at DESC
--
-- index coverage:
--   idx_properties_owner_user_id — covers owner_user_id filter
--   no composite (owner_user_id, created_at) — sort requires in-memory sort after index filter
--   property_type and name.ilike are optional secondary filters
--
-- with small table size (< 50 properties per owner), in-memory sort is negligible.
-- verdict: ACCEPTABLE. composite index not worth the overhead at this scale.

-- ============================================================================
-- flow 3: LEASE CREATION WIZARD — property selection, unit selection, tenant selection
-- ============================================================================
-- step 1 (property selection):
--   .from('properties').select('*').neq('status', 'inactive')
--   RLS: WHERE owner_user_id = auth.uid()
--   coverage: idx_properties_owner_user_id — OK
--
-- step 2 (unit selection by property):
--   .from('units').select('*').eq('property_id', $1).neq('status', 'inactive')
--   RLS: owner_user_id check
--   coverage: idx_units_property_id — OK
--
-- step 3 (tenant selection):
--   .from('tenants').select('*, users!inner(*)').or('full_name.ilike, email.ilike')
--   RLS: complex join through lease_tenants → leases → properties
--   coverage: idx_tenants_user_id for RLS — OK
--
-- step 4 (lease INSERT):
--   INSERT into leases — no index concern
--   INSERT into lease_tenants — uses lease_tenants_insert_owner policy (fixed in phase 3)
--
-- verdict: FULLY INDEXED. no changes needed.

-- ============================================================================
-- flow 4: TENANT LIST — with property filter and search
-- ============================================================================
-- frontend query:
--   .from('tenants').select('*, users!inner(...), lease_tenants(...)')
--   .or('users.full_name.ilike, users.email.ilike')
--   .order('created_at', { ascending: false })
--
-- RLS adds owner check via lease_tenants → leases → owner_user_id
--
-- index coverage:
--   idx_lease_tenants_tenant_id — covers the join from tenants → lease_tenants
--   idx_lease_tenants_lease_id — covers the join from lease_tenants → leases
--   idx_leases_owner_status — covers owner_user_id in leases
--   users table searched by full_name/email ilike — users PK covers the FK join
--
-- the ilike searches on users table are unindexed (trigram indexes were dropped).
-- with < 200 users, sequential scan on the joined users rows is acceptable.
-- verdict: ACCEPTABLE. trigram indexes not warranted at current scale.

-- ============================================================================
-- flow 5: MAINTENANCE LIST — owner view with status/priority filters
-- ============================================================================
-- frontend query:
--   .from('maintenance_requests').select('*')
--   .eq('status', 'open')  -- or other status filter
--   .order('created_at', { ascending: false })
--
-- RLS adds: WHERE owner_user_id = auth.uid()
--
-- effective: WHERE owner_user_id = $1 AND status = 'open'
--            ORDER BY created_at DESC
--
-- index coverage:
--   idx_maintenance_requests_owner_status (owner_user_id, status) — covers BOTH filters
--   created_at sort requires in-memory sort (third column not in composite)
--
-- with < 50 maintenance requests per owner, sort overhead is negligible.
-- verdict: FULLY INDEXED for filter, acceptable sort performance.

-- ============================================================================
-- flow 6: TENANT PORTAL — amount due, payment history, active lease
-- ============================================================================
-- step 1 (resolve tenant):
--   .from('tenants').select('id').eq('user_id', auth.uid())
--   coverage: idx_tenants_user_id — OK
--
-- step 2 (active lease):
--   .from('leases').select('*, lease_tenants!inner(*)')
--   .eq('lease_tenants.tenant_id', tenant_id).eq('lease_status', 'active')
--   coverage: idx_lease_tenants_tenant_id → idx_leases_owner_status (lease_status) — OK
--
-- step 3 (amount due — MISSING INDEX):
--   .from('rent_due').select('id, amount, due_date, status')
--   .eq('lease_id', lease.id).gte('due_date', today)
--   .order('due_date', { ascending: true }).limit(1)
--
--   effective: WHERE lease_id = $1 AND due_date >= $2 ORDER BY due_date ASC LIMIT 1
--
--   current indexes:
--     idx_rent_due_due_date (due_date) — standalone, cannot seek by lease_id first
--     idx_rent_due_unit_id (unit_id) — irrelevant to this query
--     NO composite (lease_id, due_date) exists!
--
--   without the composite index, the planner must:
--     option A: seq scan rent_due, filter lease_id AND due_date, sort, limit 1
--     option B: use idx_rent_due_due_date for range, then filter lease_id (poor selectivity)
--
--   with composite (lease_id, due_date), the planner can:
--     Index Scan using idx_rent_due_lease_id_due_date
--     → seek to lease_id = $1, then scan forward from due_date >= $2
--     → return first row (LIMIT 1 = index-only stop after 1 row)
--
-- step 4 (payment history):
--   .from('rent_payments').select('*').eq('lease_id', lease.id)
--   .order('due_date', { ascending: false }).limit(50)
--   coverage: idx_rent_payments_lease_id — covers lease_id filter
--   (due_date sort is in-memory, acceptable for 50-row limit)
--
-- step 5 (already-paid check):
--   .from('rent_payments').select('id')
--   .eq('rent_due_id', record.id).eq('status', 'succeeded')
--   coverage: idx_rent_payments_rent_due_unique_succeeded — PERFECT (unique partial index)

-- ============================================================================
-- fix: add composite index for tenant portal amount-due query
-- ============================================================================
-- this is the critical missing index identified in flow 6, step 3.
-- the rent_due table is queried on (lease_id, due_date) for every tenant
-- portal page load to show the current amount due.

create index if not exists idx_rent_due_lease_id_due_date
on public.rent_due (lease_id, due_date);

comment on index idx_rent_due_lease_id_due_date is
  'Composite index for tenant portal amount-due query: '
  'SELECT ... FROM rent_due WHERE lease_id = $1 AND due_date >= $2 '
  'ORDER BY due_date ASC LIMIT 1. Enables index-only seek + early stop.';

-- update planner statistics for rent_due after adding index
analyze rent_due;
